"use client";
import { useEffect, useState } from "react";
import { Mail, User, Clock } from "lucide-react";

export default function MessagesPage() {
  const [messages, setMessages] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchMessages = async () => {
      try {
        const token = localStorage.getItem("accessToken");
        if (!token) {
          setError("Please login to view messages.");
          setLoading(false);
          return;
        }

        const res = await fetch("http://localhost:5000/messages/my", {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        });

        const data = await res.json();

        if (!res.ok) throw new Error(data.message || "Failed to load messages");

        setMessages(data.messages || []);
      } catch (err) {
        console.error(err);
        setError("Could not load messages.");
      } finally {
        setLoading(false);
      }
    };

    fetchMessages();
  }, []);

  return (
    <div className="min-h-screen bg-gray-50 p-4 sm:p-8">
      <div className="max-w-4xl mx-auto bg-white rounded-2xl shadow-xl p-6 sm:p-10">
        <div className="flex items-center gap-3 mb-8 border-b pb-4">
          <Mail className="w-8 h-8 text-blue-600" />
          <h1 className="text-3xl font-bold text-gray-800">Messages</h1>
        </div>

        {/* Loading */}
        {loading && (
          <p className="text-center text-gray-500">Loading messages...</p>
        )}

        {/* Error */}
        {error && (
          <p className="text-center text-red-500 font-medium">{error}</p>
        )}

        {/* No Messages */}
        {!loading && !error && messages.length === 0 && (
          <p className="text-center text-gray-500">You have no messages yet.</p>
        )}

        {/* Messages List */}
        <div className="space-y-4">
          {messages.map((msg) => (
            <div
              key={msg._id}
              className={`p-5 rounded-xl border transition ${
                msg.isRead
                  ? "bg-white border-gray-200"
                  : "bg-blue-50 border-blue-300"
              }`}
            >
              <div className="flex justify-between items-start">
                <div>
                  <p className="font-semibold text-gray-800 flex items-center gap-2">
                    <User className="w-4 h-4" />
                    {msg.senderName}
                  </p>
                  <p className="text-sm text-gray-500">
                    About: {msg.itemTitle}
                  </p>
                </div>

                {!msg.isRead && (
                  <span className="text-xs bg-blue-600 text-white px-2 py-1 rounded-full">
                    New
                  </span>
                )}
              </div>

              <p className="mt-3 text-gray-700">{msg.message}</p>

              <div className="mt-3 text-sm text-gray-400 flex items-center gap-1">
                <Clock className="w-4 h-4" />
                {new Date(msg.createdAt).toLocaleString()}
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
